package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testGetName_returnsCorrectName() {
    String expectedName = "TestItem";
    int quantity = 5;
    long priceInMicros = 100000L;
    String currencyCode = "USD";

    LineItem lineItem = new LineItem(expectedName, quantity, priceInMicros, currencyCode);

    String actualName = lineItem.getName();

    assertEquals(expectedName, actualName);
  }
}
